const input = $node["Input"].json;
const run = $node["Run Smoke"].json;
const stdout = run.stdout ?? '';
const stderr = run.stderr ?? '';
const evidenceMatch = stdout.match(/evidence_dir=([^\r\n]+)/);
const evidenceDir = evidenceMatch ? evidenceMatch[1].trim() : null;

return [{
  json: {
    workspace_name: input.workspace_name,
    iteration_number: input.iteration_number,
    task_text: input.task_text,
    evidence_dir: evidenceDir,
    runner: {
      code: run.code ?? null,
      stdout,
      stderr,
    },
  },
}];

const input = $node["Input"].json;
const smoke = $node["Run Smoke"].json;
const extracted = $node["Extract Evidence"].json;
const reportJsonRaw = $node["Read Report JSON"].json.stdout ?? '';
const reportMd = $node["Read Report MD"].json.stdout ?? '';

let reportJson = null;
let reportJsonError = null;
try {
  reportJson = JSON.parse(reportJsonRaw);
} catch (error) {
  reportJsonError = error.message;
}

const ok = smoke.code === 0 && Boolean(extracted.evidence_dir) && !reportJsonError;

return [{
  json: {
    status: ok ? 'GREEN' : 'GREEN_PARTIAL',
    ok,
    workspace_name: input.workspace_name,
    iteration_number: input.iteration_number,
    task_text: input.task_text,
    evidence_dir: extracted.evidence_dir,
    runner: {
      code: smoke.code ?? null,
      stdout: smoke.stdout ?? '',
      stderr: smoke.stderr ?? '',
    },
    report_json: reportJson,
    report_json_raw: reportJsonRaw,
    report_json_error: reportJsonError,
    report_md: reportMd,
    summary: ok
      ? `Smoke workflow completed for ${input.workspace_name} iter ${input.iteration_number}`
      : `Smoke workflow completed with partial issues for ${input.workspace_name} iter ${input.iteration_number}`,
  },
}];
